#!/bin/bash

# ==========================================
# SHADOW OPERATOR LAUNCHER | VPN SDC SERVER
# ==========================================

SCRIPT_TARGET="vpn_local_server_sdc.py"
PORT=8080
IP_RANGE_MIN=20
IP_RANGE_MAX=90
SCRIPT_VERSION="3.9"
UPDATE_URL="https://raw.githubusercontent.com/Pr3da7ol/ShadowVPN/main/start_vpn.bash"
AUTO_UPDATE_ENABLED="${AUTO_UPDATE_ENABLED:-0}"
FORCE_CORE_REGEN="${FORCE_CORE_REGEN:-0}"
INSTALL_OPTIONAL_TOOLS="${INSTALL_OPTIONAL_TOOLS:-0}"
VPN_SAFE32="${VPN_SAFE32:-auto}"
export DEBIAN_FRONTEND=noninteractive

# Colores
ROJO='\033[0;31m'
VERDE='\033[0;32m'
AMARILLO='\033[0;33m'
CYAN='\033[0;36m'
NC='\033[0m'

log_msg() { echo -e "${2}[${1}] ${3}${NC}"; }

is_tty_stdout() { [ -t 1 ]; }

count_pid_list() {
    # Cuenta PIDs separados por espacios/nuevas líneas.
    printf '%s\n' "$1" | tr ' ' '\n' | grep -E '^[0-9]+$' | wc -l | tr -d ' '
}

spinner_wait() {
    local seconds="${1:-1}"
    local msg="${2:-Procesando}"
    local i steps frame

    if ! is_tty_stdout; then
        sleep "$seconds"
        return 0
    fi

    steps=$((seconds * 10))
    [ "$steps" -gt 0 ] || steps=1

    for ((i=0; i<steps; i++)); do
        case $((i % 4)) in
            0) frame='|' ;;
            1) frame='/' ;;
            2) frame='-' ;;
            3) frame='\\' ;;
        esac
        printf "\r${CYAN}[MAINT] %s %s${NC}" "$msg" "$frame"
        sleep 0.1
    done
    printf "\r\033[K"
}

has_cmd() { command -v "$1" >/dev/null 2>&1; }

termux_arch() {
    if has_cmd dpkg; then
        dpkg --print-architecture 2>/dev/null && return 0
    fi
    uname -m 2>/dev/null || echo "unknown"
}

is_32bit_arch() {
    case "$(termux_arch)" in
        arm|armhf|armv7l|i686|x86) return 0 ;;
        *) return 1 ;;
    esac
}

safe32_mode_enabled() {
    case "${VPN_SAFE32}" in
        1|true|TRUE|yes|YES|on|ON) return 0 ;;
        0|false|FALSE|no|NO|off|OFF) return 1 ;;
        auto|AUTO|"")
            is_32bit_arch
            return $?
            ;;
        *)
            # Valor desconocido: fallback seguro solo si detecta 32-bit
            is_32bit_arch
            return $?
            ;;
    esac
}

contains_cannot_link() {
    printf '%s' "$1" | grep -Eqi 'cannot link executable|cannon link executable'
}

log_cannot_link_hint() {
    local context="${1:-comando}"
    log_msg "WARN" "$AMARILLO" "Detectado 'CANNOT LINK EXECUTABLE' durante: $context"
    if is_32bit_arch; then
        log_msg "WARN" "$AMARILLO" "Entorno 32-bit detectado ($(termux_arch)). Esto suele pasar por binario/librería incompatible con la arquitectura."
    fi
    log_msg "INFO" "$CYAN" "Se intentará fallback (pip/fuente) cuando sea posible."
}

pkg_install_cmd() {
    # Ejecuta pkg install mostrando diagnóstico si aparece CANNOT LINK EXECUTABLE.
    if ! has_cmd pkg; then
        return 1
    fi
    local out rc
    out="$(pkg install "$@" 2>&1)"
    rc=$?
    if [ $rc -ne 0 ]; then
        if contains_cannot_link "$out"; then
            log_cannot_link_hint "pkg install $*"
        fi
        return $rc
    fi
    return 0
}

termux_pkg_install() {
    # Instala paquetes solo si estamos en Termux (pkg disponible).
    if ! has_cmd pkg; then
        return 0
    fi
    local pkg_name="$1"
    if [ -z "$pkg_name" ]; then
        return 0
    fi
    if dpkg -s "$pkg_name" >/dev/null 2>&1; then
        return 0
    fi
    log_msg "INSTALL" "$CYAN" "Instalando paquete Termux: $pkg_name"
    pkg_install_cmd "$pkg_name" -y || {
        log_msg "WARN" "$AMARILLO" "No se pudo instalar paquete '$pkg_name' (continuando)."
        return 1
    }
    return 0
}

pip_install_py() {
    # Usa python3 -m pip para evitar confusiones entre pip/pip3.
    local out rc
    out="$(python3 -m pip install --no-cache-dir "$@" 2>&1)"
    rc=$?
    if [ $rc -ne 0 ]; then
        if contains_cannot_link "$out"; then
            log_cannot_link_hint "python3 -m pip install $*"
        fi
        # Mostrar últimas líneas ayuda a depurar sin inundar la terminal.
        echo "$out" | tail -n 8
        return $rc
    fi
    return 0
}

# --- AUTO-UPDATE ---
get_self_path() {
    local p="$0"
    local resolved=""
    if command -v readlink &> /dev/null; then
        resolved="$(readlink -f "$p" 2>/dev/null)"
    fi
    if [ -z "$resolved" ] && command -v realpath &> /dev/null; then
        resolved="$(realpath "$p" 2>/dev/null)"
    fi
    [ -n "$resolved" ] && echo "$resolved" || echo "$p"
}

fetch_remote_script() {
    local url="$1"
    local out="$2"
    if command -v curl &> /dev/null; then
        curl -fsSL "$url" -o "$out"
    elif command -v wget &> /dev/null; then
        wget -qO "$out" "$url"
    else
        return 1
    fi
}

extract_version() {
    local file="$1"
    local v=""
    v="$(grep -m1 '^SCRIPT_VERSION=' "$file" 2>/dev/null | cut -d'"' -f2)"
    if [ -z "$v" ]; then
        v="$(grep -m1 -E 'REPARACIÓN DE EMERGENCIA \(V[0-9.]+\)' "$file" 2>/dev/null | sed -E 's/.*\(V([0-9.]+)\).*/\1/')"
    fi
    echo "$v"
}

auto_update() {
    local self_path tmp_file remote_version
    self_path="$(get_self_path)"
    tmp_file="/tmp/start_vpn.bash.$$"

    if ! fetch_remote_script "$UPDATE_URL" "$tmp_file"; then
        echo -e "${AMARILLO}[!] Auto-update no disponible (curl/wget o red).${NC}"
        return 0
    fi

    remote_version="$(extract_version "$tmp_file")"
    if cmp -s "$tmp_file" "$self_path" 2>/dev/null; then
        if [ -n "$remote_version" ]; then
            echo -e "${VERDE}[OK] Script en ultima version (v${remote_version}).${NC}"
        else
            echo -e "${VERDE}[OK] Script en ultima version.${NC}"
        fi
        rm -f "$tmp_file"
        return 0
    fi

    if [ -n "$remote_version" ]; then
        echo -e "${CYAN}[*] Update detectado: v${SCRIPT_VERSION} -> v${remote_version}${NC}"
    else
        echo -e "${CYAN}[*] Update detectado por contenido remoto.${NC}"
    fi
    if cp "$tmp_file" "$self_path" 2>/dev/null; then
        chmod +x "$self_path" 2>/dev/null
        echo -e "${VERDE}[OK] Script actualizado. Re-lanzando...${NC}"
        rm -f "$tmp_file"
        exec "$self_path" "$@"
    else
        echo -e "${ROJO}[X] No se pudo escribir en: $self_path${NC}"
        rm -f "$tmp_file"
        return 0
    fi
}

refresh_core_payload() {
    if [ "$FORCE_CORE_REGEN" != "1" ]; then
        log_msg "SYNC" "$CYAN" "Conservando $SCRIPT_TARGET (FORCE_CORE_REGEN=0)."
        return 0
    fi
    if [ -f "$SCRIPT_TARGET" ]; then
        log_msg "SYNC" "$CYAN" "Eliminando $SCRIPT_TARGET para forzar descarga/reconstruccion..."
        if ! rm -f "$SCRIPT_TARGET"; then
            log_msg "WARN" "$AMARILLO" "No se pudo eliminar $SCRIPT_TARGET. Se intentara continuar."
        fi
    fi
}

# --- VERIFICACIÓN DE RANGO IP (IFCONFIG) ---
get_ifconfig_ips() {
    ifconfig 2>/dev/null \
        | grep -Eo 'inet (addr:)?([0-9]{1,3}\.){3}[0-9]{1,3}' \
        | awk '{print $2}' \
        | sed 's/^addr://g' \
        | sort -u
}

get_rmnet0_ip() {
    local ip=""
    ip="$(ifconfig rmnet0 2>/dev/null \
        | grep -Eo 'inet (addr:)?([0-9]{1,3}\.){3}[0-9]{1,3}' \
        | awk '{print $2}' \
        | sed 's/^addr://g' \
        | head -n1)"
    if [ -n "$ip" ]; then
        echo "$ip"
        return 0
    fi
    ifconfig 2>/dev/null | awk '
        $1 ~ /^rmnet0/ {show=1; next}
        show && $1 ~ /^$/ {exit}
        show && $1=="inet" {print $2; exit}
    ' | sed 's/^addr://g'
}

get_wifi_ip() {
    local ip=""
    ip="$(ifconfig wlan0 2>/dev/null \
        | grep -Eo 'inet (addr:)?([0-9]{1,3}\.){3}[0-9]{1,3}' \
        | awk '{print $2}' \
        | sed 's/^addr://g' \
        | head -n1)"
    if [ -n "$ip" ]; then
        echo "$ip"
        return 0
    fi
    ifconfig 2>/dev/null | awk '
        $1 ~ /^wlan[0-9]+/ {iface=1; next}
        iface && $1 ~ /^$/ {iface=0}
        iface && $1=="inet" {print $2; exit}
    ' | sed 's/^addr://g'
}

is_private_lan_ip() {
    local ip="$1"
    local o1 o2 o3 o4
    IFS='.' read -r o1 o2 o3 o4 <<< "$ip"
    case "$o1" in
        192)
            [ "$o2" = "168" ] && return 0 || return 1
            ;;
        172)
            case "$o2" in
                ''|*[!0-9]*) return 1 ;;
            esac
            [ "$o2" -ge 16 ] && [ "$o2" -le 31 ] && return 0 || return 1
            ;;
        10)
            # 10/8 puede ser WiFi/LAN o datos; se usa como apoyo si no existe rmnet0.
            return 0
            ;;
        *)
            return 1
            ;;
    esac
}

ip_in_recommended_range() {
    local ip="$1"
    local o1 o2 o3 o4
    IFS='.' read -r o1 o2 o3 o4 <<< "$ip"
    [ "$o1" = "10" ] || return 1
    case "$o2" in
        ''|*[!0-9]*) return 1 ;;
    esac
    [ "$o2" -ge "$IP_RANGE_MIN" ] && [ "$o2" -le "$IP_RANGE_MAX" ]
}

check_ip_range_ifconfig() {
    if ! command -v ifconfig &> /dev/null; then
        echo -e "${AMARILLO}[!] ifconfig no disponible. Omitiendo verificacion de rango.${NC}"
        return 0
    fi

    local rmnet_ip wifi_ip current_ip ok match_ip
    rmnet_ip="$(get_rmnet0_ip)"
    wifi_ip="$(get_wifi_ip)"
    ok=1

    if [ -n "$rmnet_ip" ]; then
        current_ip="$rmnet_ip"
        if ip_in_recommended_range "$rmnet_ip"; then
            ok=0
            match_ip="$rmnet_ip"
        fi
    else
        local ips primary_ip
        ips="$(get_ifconfig_ips)"
        if [ -z "$ips" ]; then
            echo -e "${AMARILLO}[!] No se detectaron IPs con ifconfig. Omitiendo verificacion.${NC}"
            return 0
        fi
        primary_ip=""
        for ip in $ips; do
            if [ "$ip" != "127.0.0.1" ]; then
                primary_ip="$ip"
                break
            fi
        done
        if [ -z "$primary_ip" ]; then
            primary_ip="$(echo "$ips" | head -n1)"
        fi
        current_ip="$primary_ip"
        if [ -n "$primary_ip" ] && ip_in_recommended_range "$primary_ip"; then
            ok=0
            match_ip="$primary_ip"
        fi
    fi

    if [ "$ok" -eq 0 ]; then
        echo -e "${VERDE}[OK] IP EN RANGO SUGERIDO: ${NC}$match_ip"
        echo -e "${CYAN}Rango sugerido: 10.${IP_RANGE_MIN} - 10.${IP_RANGE_MAX}${NC}"
        return 0
    fi

    # Si es WiFi/LAN (sin rmnet0) no pedir confirmación de "forzar".
    if [ -z "$rmnet_ip" ] && [ -n "$current_ip" ]; then
        if { [ -n "$wifi_ip" ] && [ "$current_ip" = "$wifi_ip" ]; } || is_private_lan_ip "$current_ip"; then
            echo -e "${VERDE}[OK] Red WiFi/LAN detectada: ${NC}$current_ip"
            echo -e "${CYAN}Verificación de rango móvil omitida en WiFi/LAN.${NC}"
            return 0
        fi
    fi

    if [ -z "$current_ip" ]; then
        current_ip="N/A"
    fi
    echo -e "${ROJO}[X] IP FUERA DE RANGO SUGERIDO: ${NC}$current_ip"
    echo -e "${CYAN}Rango sugerido: 10.${IP_RANGE_MIN} - 10.${IP_RANGE_MAX}${NC}"
    echo -e "${CYAN}[*] PROTOCOLO DE RECUPERACION DE RANGO:${NC}"
    echo -e "${CYAN}    1) PON EL TELEFONO EN MODO AVION (10-15s).${NC}"
    echo -e "${CYAN}    2) DESACTIVA MODO AVION Y ESPERA NUEVA IP.${NC}"
    echo -e "${CYAN}    3) VERIFICA CON ifconfig Y REINTENTA.${NC}"
    echo -e "${AMARILLO}[!] Continuar podria afectar rendimiento o consumo de datos.${NC}"
    read -r -p ">> Forzar ejecucion? (s/N): " confirm
    if [ "$confirm" != "s" ]; then
        echo -e "${ROJO}[!] Operacion abortada por verificacion de rango.${NC}"
        exit 0
    fi
    echo -e "${AMARILLO}[!] MODO FORZADO ACTIVADO.${NC}"
}

# --- CONTROL DE PUERTO ---
port_in_use() {
    if command -v ss &> /dev/null; then
        if ss -ltn "sport = :$PORT" 2>/dev/null | grep -q ":$PORT"; then
            return 0
        fi
    fi
    if command -v lsof &> /dev/null; then
        if lsof -iTCP:"$PORT" -sTCP:LISTEN -t &> /dev/null; then
            return 0
        fi
    fi
    if command -v fuser &> /dev/null; then
        if fuser -n tcp "$PORT" &> /dev/null; then
            return 0
        fi
    fi

    # Fallback para Termux cuando ss/lsof/fuser no pueden leer /proc por permisos.
    if command -v python3 &> /dev/null; then
        python3 - "$PORT" >/dev/null 2>&1 <<'PY'
import errno, socket, sys
port = int(sys.argv[1])
s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
try:
    s.bind(("0.0.0.0", port))
except OSError as e:
    raise SystemExit(0 if e.errno in (errno.EADDRINUSE, 98) else 1)
else:
    s.close()
    raise SystemExit(1)
PY
        return $?
    fi

    return 1
}

find_vpn_pids_by_signature() {
    local pids=""

    if command -v pgrep &> /dev/null; then
        pids="$(pgrep -f "python(3)? .*${SCRIPT_TARGET}.*--port[ =]${PORT}" 2>/dev/null | sort -u)"
    fi

    if [ -z "$pids" ] && command -v ps &> /dev/null; then
        pids="$(ps -ef 2>/dev/null | awk -v script="$SCRIPT_TARGET" -v port="$PORT" '
            $0 ~ /python/ && index($0, script) && ($0 ~ ("--port " port) || $0 ~ ("--port=" port)) {print $2}
        ' | sort -u)"
    fi

    printf '%s\n' "$pids" | awk 'NF'
}

kill_existing_vpn_instances() {
    local pids clean_pids pid_count
    pids="$(find_vpn_pids_by_signature)"
    clean_pids="$(printf '%s\n' "$pids" | grep -E '^[0-9]+$' | sort -u | tr '\n' ' ' | sed 's/[[:space:]]*$//')"

    if [ -n "$clean_pids" ]; then
        pid_count="$(count_pid_list "$clean_pids")"
        log_msg "MAINT" "$AMARILLO" "Se detectaron ${pid_count} instancia(s) previas de Shadow VPN. Cerrando para liberar el puerto..."
        log_msg "DETAIL" "$CYAN" "PID(s) VPN detectados: $clean_pids"
        kill $clean_pids 2>/dev/null || true
        spinner_wait 1 "Cerrando instancias previas"
        if port_in_use; then
            log_msg "MAINT" "$ROJO" "El puerto sigue ocupado. Aplicando cierre forzado a las instancias anteriores..."
            kill -9 $clean_pids 2>/dev/null || true
            spinner_wait 1 "Forzando cierre"
        fi
    fi
}

kill_port() {
    local pids="" clean_pids=""
    if command -v ss &> /dev/null; then
        pids=$(ss -ltnp "sport = :$PORT" 2>/dev/null | awk -F'pid=' 'NR>1{split($2,a,","); print a[1]}' | sort -u)
    elif command -v lsof &> /dev/null; then
        pids=$(lsof -iTCP:"$PORT" -sTCP:LISTEN -t 2>/dev/null | sort -u)
    elif command -v fuser &> /dev/null; then
        pids=$(fuser -n tcp "$PORT" 2>/dev/null)
    fi
    clean_pids="$(printf '%s\n' "$pids" | tr ' ' '\n' | grep -E '^[0-9]+$' | sort -u | tr '\n' ' ' | sed 's/[[:space:]]*$//')"
    if [ -n "$clean_pids" ]; then
        log_msg "MAINT" "$AMARILLO" "Puerto $PORT en uso. Intentando cerrar proceso(s) que lo ocupan..."
        log_msg "DETAIL" "$CYAN" "PID(s) por puerto detectados: $clean_pids"
        kill $clean_pids 2>/dev/null
        spinner_wait 1 "Liberando puerto $PORT"
        if port_in_use; then
            log_msg "MAINT" "$ROJO" "El puerto $PORT sigue ocupado. Aplicando cierre forzado..."
            kill -9 $clean_pids 2>/dev/null
            spinner_wait 1 "Forzando liberación"
        fi
    fi

    # Fallback por firma de proceso cuando ss/lsof/fuser no pueden obtener PID.
    if port_in_use; then
        kill_existing_vpn_instances
    fi
}

# --- 1. GENERACIÓN DEL PAYLOAD (Self-Extracting) ---
generate_payload() {
    log_msg "SYSTEM" "$CYAN" "Verificando integridad del núcleo..."

    if [ -f "$SCRIPT_TARGET" ] && [ "$FORCE_CORE_REGEN" != "1" ]; then
        log_msg "GEN" "$VERDE" "Núcleo local detectado. Se reutiliza $SCRIPT_TARGET."
        return 0
    fi

    log_msg "GEN" "$AMARILLO" "Regenerando $SCRIPT_TARGET desde payload embebido (ULTRA SECURE)..."

    # INICIO DEL BLOQUE PYTHON PROTEGIDO V2
    cat << 'EOF' > "$SCRIPT_TARGET"
# encriptado por @Th3_Pr3da70l
from marshal import loads as dzx;exec(dzx(b'\xe3\x00\x00\x00\x00\x00\x00\x00\x00\x00\x00\x00\x00\x05\x00\x00\x00\x00\x00\x00\x00\xf3,\x00\x00\x00\x97\x00d\x00d\x01l\x00m\x01Z\x02\x01\x00\x02\x00e\x03\x02\x00e\x02d\x02\xab\x01\x00\x00\x00\x00\x00\x00\xab\x01\x00\x00\x00\x00\x00\x00\x01\x00y\x03)\x04\xe9\x00\x00\x00\x00)\x01\xda\tb16decodes\x88\xe55\)\x04\xda\x06base64r\x03\x00\x00\x00\xda\x03dzx\xda\x04exec\xa9\x00\xf3\x00\x00\x00\x00z\x08<capa_4>\xda\x08<module>r\t\x00\x00\x00\x01\x00\x00\x00s$\x00\x00\x00\xf0\x03\x01\x01\x01\xdd\x00#\xa1D\xa9\x13\xf0\x00\x00.yV^\r\xf3\x00\x00*zV^\r\xf5\x00\x00%{V^\rr\x08\x00\x00\x00'))
# youll tire
EOF
    # FIN DEL BLOQUE PYTHON PROTEGIDO V2

    chmod +x "$SCRIPT_TARGET" 2>/dev/null
    log_msg "SUCCESS" "$VERDE" "Núcleo materializado con cifrado SHADOW V2."
}

# --- 2. VERIFICACIÓN DE ENTORNO ---
check_env() {
    log_msg "SETUP" "$AMARILLO" "Verificando entorno de ejecución..."
    log_msg "INFO" "$CYAN" "Arquitectura detectada: $(termux_arch)$(is_32bit_arch && echo ' (32-bit)' || true)"
    if safe32_mode_enabled; then
        log_msg "INFO" "$CYAN" "Modo compatibilidad 32-bit: ACTIVADO (VPN_SAFE32=${VPN_SAFE32})"
        log_msg "INFO" "$CYAN" "Se priorizarán fallbacks y se evitarán algunos paquetes nativos conflictivos."
    else
        log_msg "INFO" "$CYAN" "Modo compatibilidad 32-bit: desactivado (VPN_SAFE32=${VPN_SAFE32})"
    fi
    
    # Python
    if ! command -v python3 &> /dev/null; then
        log_msg "INSTALL" "$AMARILLO" "Instalando Python3..."
        if ! pkg_install_cmd python3 -y; then
            log_msg "WARN" "$AMARILLO" "No se pudo instalar Python3 con pkg."
        fi
    fi

    # Paquetes obligatorios (mínimos)
    if has_cmd pkg; then
        termux_pkg_install python-pip || true
    fi

    # Herramientas opcionales (diagnóstico / update / utilidades de puerto)
    # No son necesarias para que la VPN funcione.
    if [ "$INSTALL_OPTIONAL_TOOLS" = "1" ] && has_cmd pkg; then
        log_msg "SETUP" "$CYAN" "Instalando herramientas opcionales de Termux..."
        termux_pkg_install net-tools || true   # ifconfig
        termux_pkg_install iproute2 || true    # ss
        termux_pkg_install lsof || true
        termux_pkg_install psmisc || true      # fuser
        termux_pkg_install curl || true
        termux_pkg_install wget || true
    else
        log_msg "INFO" "$CYAN" "Herramientas opcionales (iproute2/net-tools/lsof/psmisc/curl/wget) omitidas. Usa INSTALL_OPTIONAL_TOOLS=1 si las quieres."
    fi

    # Pip
    if ! python3 -m pip --version >/dev/null 2>&1; then
        log_msg "INSTALL" "$CYAN" "Instalando pip para Python3..."
        if has_cmd pkg; then
            pkg_install_cmd python-pip -y || true
        fi
    fi

    if ! python3 -m pip --version >/dev/null 2>&1; then
        log_msg "WARN" "$AMARILLO" "pip no está disponible. Se intentará continuar con paquetes nativos."
    fi

    # Cryptography
    if ! python3 -c "import cryptography" &> /dev/null; then
        log_msg "INSTALL" "$CYAN" "Instalando librería 'cryptography'..."
        if safe32_mode_enabled; then
             log_msg "INFO" "$CYAN" "SAFE32: omitiendo paquete nativo python-cryptography; intentando pip."
             if ! pip_install_py cryptography; then
                 log_msg "WARN" "$AMARILLO" "SAFE32: cryptography por pip falló. Intentando toolchain y reintento..."
                 pkg_install_cmd build-essential openssl libffi rust binutils -y || true
                 pip_install_py cryptography || true
             fi
        elif ! pkg_install_cmd python-cryptography -y; then
             log_msg "WARN" "$AMARILLO" "Fallo nativo. Intentando compilación..."
             pkg_install_cmd build-essential openssl libffi rust binutils -y || true
             pip_install_py cryptography
        fi
    fi

    # cffi backend (necesario para cryptography en varios runtimes)
    if ! python3 -c "import cffi, _cffi_backend" &> /dev/null; then
        log_msg "INSTALL" "$CYAN" "Instalando backend cffi..."
        if safe32_mode_enabled; then
            log_msg "INFO" "$CYAN" "SAFE32: omitiendo paquete nativo python-cffi; intentando pip."
            pip_install_py cffi || true
        elif ! pkg_install_cmd python-cffi -y; then
            log_msg "WARN" "$AMARILLO" "Fallo nativo cffi. Intentando pip..."
            pip_install_py cffi
        fi
    fi

    # Requests + BeautifulSoup
    if ! python3 -c "import requests, bs4" &> /dev/null; then
        log_msg "INSTALL" "$CYAN" "Instalando librerías 'requests' y 'bs4'..."
        pip_install_py requests beautifulsoup4
    fi

    # httpx (soportes fb / APIs)
    if ! python3 -c "import httpx" &> /dev/null; then
        log_msg "INSTALL" "$CYAN" "Instalando 'httpx'..."
        pip_install_py httpx
    fi

    # cloudscraper (soporte playstore)
    if ! python3 -c "import cloudscraper" &> /dev/null; then
        log_msg "INSTALL" "$CYAN" "Instalando 'cloudscraper'..."
        pip_install_py cloudscraper
    fi

    # yt-dlp (soporte YouTube)
    if ! python3 -c "import yt_dlp" &> /dev/null; then
        log_msg "INSTALL" "$CYAN" "Instalando 'yt-dlp'..."
        pip_install_py yt-dlp
    fi

    # tqdm (descargadores auxiliares)
    if ! python3 -c "import tqdm" &> /dev/null; then
        log_msg "INSTALL" "$CYAN" "Instalando 'tqdm'..."
        pip_install_py tqdm
    fi

    # Crypto / Cryptodome (algunos decodificadores usan uno u otro namespace)
    if ! python3 -c "import Crypto" &> /dev/null; then
        log_msg "INSTALL" "$CYAN" "Instalando 'pycryptodome' (namespace Crypto)..."
        if has_cmd pkg; then
            if safe32_mode_enabled; then
                log_msg "INFO" "$CYAN" "SAFE32: omitiendo paquete nativo python-pycryptodome; intentando pip."
                pip_install_py pycryptodome || true
            else
                pkg_install_cmd python-pycryptodome -y || pip_install_py pycryptodome
            fi
        else
            pip_install_py pycryptodome
        fi
    fi

    if ! python3 -c "import Cryptodome" &> /dev/null; then
        log_msg "INSTALL" "$CYAN" "Instalando 'pycryptodomex' (namespace Cryptodome)..."
        pip_install_py pycryptodomex
    fi

    # Validación final de módulos reales usados por la VPN
    if ! python3 - <<'PY' >/dev/null 2>&1
mods = ["requests", "bs4", "cryptography", "cffi", "httpx", "cloudscraper", "yt_dlp", "tqdm"]
missing = []
for m in mods:
    try:
        __import__(m)
    except Exception:
        missing.append(m)
try:
    __import__("Crypto")
except Exception:
    try:
        __import__("Cryptodome")
    except Exception:
        missing.append("Crypto/Cryptodome")
if missing:
    raise SystemExit("Faltan módulos: " + ", ".join(missing))
PY
    then
        log_msg "WARN" "$AMARILLO" "Algunos módulos siguen faltando. Revisa python3 -m pip install manual."
    else
        log_msg "OK" "$VERDE" "Dependencias Python verificadas correctamente."
    fi
}

# --- 3. EJECUCIÓN ---
if [ "$AUTO_UPDATE_ENABLED" = "1" ]; then
    auto_update "$@"
else
    log_msg "SYNC" "$CYAN" "Auto-update desactivado (AUTO_UPDATE_ENABLED=0)."
fi
refresh_core_payload
clear
echo -e "${CYAN}   ___  ___  _  __   ___  ___  ___ ${NC}"
echo -e "${CYAN}  / _ \/ _ \/ |/ /  / _ \/ _ \/ _ |${NC}"
echo -e "${CYAN} / // / ___/    /  / // / ___/ __ |${NC}"
echo -e "${CYAN}/____/_/   /_/|_/  /____/_/   /_/ |_|${NC}"
echo -e "${CYAN}       SHADOW INFRASTRUCTURE       ${NC}"
echo ""

generate_payload
check_env
check_ip_range_ifconfig
log_msg "LAUNCH" "$VERDE" "Iniciando Servidor VPN SDC (Shadow V2)..."
echo -e "${CYAN}====================================================${NC}"

launch_vpn() {
    kill_existing_vpn_instances

    if port_in_use; then
        log_msg "MAINT" "$AMARILLO" "Puerto $PORT ocupado al iniciar. Se limpiará y se relanzará Shadow VPN."
        kill_port
        spinner_wait 1 "Preparando relanzamiento"
    fi

    if port_in_use; then
        log_msg "ERROR" "$ROJO" "No se pudo liberar el puerto $PORT. Revisa qué app lo está usando y reintenta."
        return 98
    fi

    PYTHONNODEBUGRANGES=1 python3 "$SCRIPT_TARGET" --port "$PORT" </dev/null &
    VPN_PID=$!
    log_msg "PID" "$VERDE" "VPN lanzada con PID: ($VPN_PID) en puerto $PORT"
    wait "$VPN_PID"
    return $?
}

STOP_REQUESTED=0
RESTART_DELAY_SECONDS="${RESTART_DELAY_SECONDS:-2}"
SUPERVISOR_PID_FILE=""

init_supervisor_pid_file() {
    local base_dir=""
    if command -v pwd >/dev/null 2>&1; then
        base_dir="$(pwd 2>/dev/null)"
    fi
    [ -n "$base_dir" ] || base_dir="."

    SUPERVISOR_PID_FILE="${base_dir}/.shadow_vpn_sdc_${PORT}.supervisor.pid"

    # Fallback por si el cwd no fuera escribible.
    if ! : > "$SUPERVISOR_PID_FILE" 2>/dev/null; then
        SUPERVISOR_PID_FILE="./.shadow_vpn_sdc_${PORT}.supervisor.pid"
        : > "$SUPERVISOR_PID_FILE" 2>/dev/null || true
    fi
}

pid_is_alive() {
    local pid="$1"
    [ -n "$pid" ] && kill -0 "$pid" 2>/dev/null
}

cleanup_supervisor_pid_file() {
    if [ -f "$SUPERVISOR_PID_FILE" ] && [ "$(cat "$SUPERVISOR_PID_FILE" 2>/dev/null)" = "$$" ]; then
        rm -f "$SUPERVISOR_PID_FILE" 2>/dev/null || true
    fi
}

stop_previous_supervisor() {
    local old_pid="" other_pids="" pid_count=""
    if [ -f "$SUPERVISOR_PID_FILE" ]; then
        old_pid="$(tr -cd '0-9' < "$SUPERVISOR_PID_FILE" 2>/dev/null)"
    fi

    if [ -n "$old_pid" ] && [ "$old_pid" != "$$" ] && pid_is_alive "$old_pid"; then
        log_msg "MAINT" "$AMARILLO" "Se detectó un supervisor anterior (PID $old_pid). Se cerrará para evitar relanzados duplicados."
        kill "$old_pid" 2>/dev/null || true
        spinner_wait 1 "Cerrando supervisor anterior"
        if pid_is_alive "$old_pid"; then
            log_msg "MAINT" "$ROJO" "El supervisor anterior sigue activo. Aplicando cierre forzado (PID $old_pid)..."
            kill -9 "$old_pid" 2>/dev/null || true
            spinner_wait 1 "Forzando cierre de supervisor"
        fi
    fi

    rm -f "$SUPERVISOR_PID_FILE" 2>/dev/null || true
    printf '%s\n' "$$" > "$SUPERVISOR_PID_FILE" 2>/dev/null || true

    if command -v pgrep &> /dev/null; then
        other_pids="$(pgrep -f 'start_vpn\.bash' 2>/dev/null | grep -vx "$$" | sort -u | tr '\n' ' ' | sed 's/[[:space:]]*$//')"
        if [ -n "$other_pids" ]; then
            pid_count="$(count_pid_list "$other_pids")"
            log_msg "MAINT" "$AMARILLO" "Se detectaron ${pid_count} launcher(s) anteriores activos. Se cerrarán para evitar conflicto."
            log_msg "DETAIL" "$CYAN" "PID(s) launcher detectados: $other_pids"
            kill $other_pids 2>/dev/null || true
            spinner_wait 1 "Cerrando launchers anteriores"
            other_pids="$(printf '%s\n' "$other_pids" | tr ' ' '\n' | grep -E '^[0-9]+$' | sort -u | tr '\n' ' ' | sed 's/[[:space:]]*$//')"
            if [ -n "$other_pids" ]; then
                kill -9 $other_pids 2>/dev/null || true
                spinner_wait 1 "Verificando cierre final"
            fi
        fi
    fi

    # Limpia procesos Python huérfanos de runs anteriores.
    kill_existing_vpn_instances
}

handle_shutdown() {
    STOP_REQUESTED=1
    log_msg "STOP" "$AMARILLO" "Señal de salida recibida. Deteniendo supervisor VPN..."
    if [ -n "${VPN_PID:-}" ]; then
        kill "$VPN_PID" 2>/dev/null || true
    fi
    cleanup_supervisor_pid_file
}

supervise_vpn() {
    local exit_code=0
    local attempt=0
    while true; do
        attempt=$((attempt + 1))
        if [ "$attempt" -gt 1 ]; then
            log_msg "RETRY" "$CYAN" "Reintento #$attempt: relanzando VPN..."
        fi

        launch_vpn
        exit_code=$?

        if [ "$STOP_REQUESTED" -eq 1 ]; then
            return "$exit_code"
        fi

        log_msg "WARN" "$ROJO" "La VPN se detuvo (exit=$exit_code). Reintentando en ${RESTART_DELAY_SECONDS}s..."
        sleep "$RESTART_DELAY_SECONDS"
    done
}

trap 'handle_shutdown' INT TERM
trap 'cleanup_supervisor_pid_file' EXIT
init_supervisor_pid_file
stop_previous_supervisor
supervise_vpn
